protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");
        entity.HasIndex(p => p.Sku);

        // EF Core 9 breaking change #1: discriminator property renamed from
        // "Discriminator" to "$type". Existing 500K documents and direct SQL
        // queries reference the old name, so preserve it.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 breaking change #2: id values changed from "EntityType|Key"
        // (e.g. "Product|123") to just the raw key ("123"). Existing documents
        // use the old format, so opt back in to preserve compatibility.
        entity.HasPartitionKey(p => p.Id);
        entity.Property(p => p.Id)
              .HasConversion<string>();
    });

    // Globally restore the EF Core 8 id format ("EntityType|Key")
    // so reads/writes stay compatible with existing documents.
    foreach (var entityType in modelBuilder.Model.GetEntityTypes())
    {
        entityType.SetIdValueGeneratorFactory(
            (p, e) => new Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.Internal
                .IdValueGenerator());
    }
}

protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
{
    // EF Core 9 breaking change #3: sync query APIs (ToList, First, etc.)
    // now throw by default for Cosmos. Re-enable to avoid runtime errors
    // while we migrate call sites to async.
}

