            // (e.g. "Product|123") to just the raw key ("123"). Existing documents
            // use the old format, so restore it via a custom value generator on
            // the Cosmos __id shadow property.
            entity.Property<string>("__id")
                  .HasValueGenerator<LegacyCosmosIdValueGenerator>();
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // EF Core 9 breaking change #3: sync query APIs (ToList, First, etc.)
        // now throw by default for Cosmos. Call sites have been migrated to async.
    }
}

